123: void Cluster::checkIdleSubCluster() {
124:   ASSERT(main_thread_dispatcher_.isThreadSafe());
125:   {
126:     // TODO: try read lock first.
127:     absl::WriterMutexLock lock{&cluster_map_lock_};
128:     for (auto it = cluster_map_.cbegin(); it != cluster_map_.cend();) {
129:       if (it->second->checkIdle()) {
130:         auto cluster_name = it->first;
131:         ENVOY_LOG(debug, "cluster='{}' removing from cluster_map & cluster manager", cluster_name);
132:         cluster_map_.erase(it++);
133:         cm_.removeCluster(cluster_name);
134:       } else {
135:         ++it;
136:       }
137:     }
138:   }
139:   idle_timer_->enableTimer(sub_cluster_ttl_);
