326: void Cluster::onDnsHostRemove(const std::string& host) {
327:   Upstream::HostVector hosts_removed;
328:   {
329:     absl::WriterMutexLock lock{&host_map_lock_};
330:     const auto host_map_it = host_map_.find(host);
331:     ASSERT(host_map_it != host_map_.end());
332:     hosts_removed.emplace_back(host_map_it->second.logical_host_);
333:     host_map_.erase(host);
